            reversed = reversed * 10 + digit.toLong()
            temp /= 10
        }
        return reversed
    }

    val r = reverseNumber(n)

    val start = minOf(n, r)
    val end = maxOf(n, r)

    // Sieve of Eratosthenes to find primes up to 'end'
    // Since n <= 1000, end <= 1000. We can use a boolean array for simplicity.
    val limit = end.toInt()
    val isPrime = BooleanArray(limit + 1) { true }

    if (limit >= 0) isPrime[0] = false
    if (limit >= 1) isPrime[1] = false

    var p = 2
    while (p * p <= limit) {
        if (isPrime[p]) {
            var i = p * p
            while (i <= limit) {
                isPrime[i] = false
                i += p
            }
        }
        p++
    }

    // Sum the primes in the range [start, end]
    var sum: Long = 0
    for (i in start..end) {
        val currentNum = i.toInt()
        if (currentNum <= limit && isPrime[currentNum]) {
            sum += i
        }
    }

    return sum
}
